import { Link, useNavigate, useLocation } from "react-router-dom";
import { useAuth } from "../hooks/useAuth";

const CATS = [
  { key: "hairsalon", label: "Үсчин",     icon: "✂" },
  { key: "beauty",    label: "Гоо сайхан", icon: "💄" },
  { key: "billiard",  label: "Бильярд",    icon: "🎱" },
  { key: "cafe",      label: "Кафе",       icon: "☕" },
];

export default function Navbar() {
  const { user, logout, isAdmin } = useAuth();
  const nav = useNavigate();
  const loc = useLocation();

  return (
    <nav style={{
      position: "sticky", top: 0, zIndex: 100,
      background: "rgba(13,17,23,0.95)", backdropFilter: "blur(8px)",
      borderBottom: "1px solid var(--border)",
      padding: "0 24px", display: "flex", alignItems: "center",
      gap: 24, height: 56,
    }}>
      {/* Logo */}
      <Link to="/" style={{ display:"flex", alignItems:"center", gap:8, textDecoration:"none" }}>
        <span style={{ fontSize:20 }}>📍</span>
        <span style={{ fontWeight:700, fontSize:18, color:"var(--text)" }}>Захиалга</span>
      </Link>

      {/* Category nav */}
      <div style={{ display:"flex", gap:4, flex:1 }}>
        {CATS.map(c => (
          <Link key={c.key} to={`/?category=${c.key}`}
            style={{
              padding:"6px 14px", borderRadius:8, fontSize:13, fontWeight:500,
              textDecoration:"none", display:"flex", alignItems:"center", gap:5,
              color: loc.search.includes(c.key) ? "var(--text)" : "var(--muted)",
              background: loc.search.includes(c.key) ? "var(--card)" : "transparent",
              border: "1px solid", borderColor: loc.search.includes(c.key) ? "var(--border)" : "transparent",
            }}>{c.icon} {c.label}</Link>
        ))}
      </div>

      {/* Right */}
      <div style={{ display:"flex", alignItems:"center", gap:12 }}>
        {user ? (
          <>
            <Link to="/my-bookings" className="btn btn-outline btn-sm">Миний захиалга</Link>
            {isAdmin && <Link to="/admin" className="btn btn-outline btn-sm">Admin</Link>}
            <div style={{
              width:36, height:36, borderRadius:"50%",
              background:"var(--blue)", display:"flex", alignItems:"center",
              justifyContent:"center", fontWeight:700, fontSize:14, cursor:"pointer"
            }} onClick={() => { if(window.confirm("Гарах уу?")) logout(); nav("/"); }}>
              {user.name?.charAt(0).toUpperCase()}
            </div>
          </>
        ) : (
          <>
            <Link to="/login" className="btn btn-outline btn-sm">Нэвтрэх</Link>
            <Link to="/register" className="btn btn-primary btn-sm">Бүртгүүлэх</Link>
          </>
        )}
      </div>
    </nav>
  );
}
